impl.spec_text:
use vstd::multiset::*;

pub proof fn insert2_fail<V>(a: V, b: V, c: V) {
    // should fail because we do not have precondition `a != b`
    assert(Multiset::empty().insert(a).insert(b).count(a) == 1); // FAILS
}

